import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { authAPI, getCurrentUser, clearAuthData } from '../api';
import './Dashboard.css';

function Dashboard() {
    const navigate = useNavigate();
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchUser();
    }, []);

    const fetchUser = async () => {
        try {
            const storedUser = getCurrentUser();
            if (storedUser) setUser(storedUser);
            const response = await authAPI.getCurrentUser();
            if (response.data.success) setUser(response.data.data);
        } catch (error) {
            if (error.response?.status === 401) handleLogout();
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        try {
            await authAPI.logout();
        } catch (error) {}
        clearAuthData();
        toast.success('Logged out');
        navigate('/login');
    };

    const getGreeting = () => {
        const hour = new Date().getHours();
        if (hour < 12) return 'Good Morning';
        if (hour < 18) return 'Good Afternoon';
        return 'Good Evening';
    };

    if (loading) return (
        <div className="dashboard-container">
            <div className="loading-spinner">Loading...</div>
        </div>
    );

    return (
        <div className="dashboard-container">
            <div className="dashboard-card">
                <div className="dashboard-header">
                    <div className="train-icon-large">🚂</div>
                    <h1>Railway Management System</h1>
                    <p className="greeting">{getGreeting()}, {user?.firstName}!</p>
                </div>
                <div className="profile-section">
                    <h2>Welcome to Your Dashboard</h2>
                    <p>You have successfully logged into the Railway Management System.</p>
                    <div className="profile-info">
                        <h3>Your Profile</h3>
                        <div className="info-grid">
                            <div><strong>Name:</strong> {user?.firstName} {user?.lastName}</div>
                            <div><strong>Email:</strong> {user?.email}</div>
                            {user?.phone && <div><strong>Phone:</strong> {user?.phone}</div>}
                            <div><strong>Role:</strong> {user?.role || 'User'}</div>
                        </div>
                    </div>
                </div>
                <div className="dashboard-footer">
                    <button onClick={handleLogout} className="logout-btn">Logout</button>
                </div>
            </div>
        </div>
    );
}

export default Dashboard;
